import xml.etree.ElementTree as ET
from typing import Dict

def validate_xml(xml_string: str) -> Dict[str, bool]:
    try:
        root = ET.fromstring(xml_string)
        
        # Define your validation rules here
        if root.tag != "document":
            return {"valid": False}
        
        for child in root:
            if not isinstance(child.tag, str):
                return {"valid": False}
            
            if child.tag.startswith("{"):
                return {"valid": False}
            
            if not all(ET.iselement(c) for c in child):
                return {"valid": False}
        
        return {"valid": True}
    
    except ET.ParseError as e:
        return {"error": str(e)}

def process_xml(xml_string: str) -> Dict[str, bool]:
    result = validate_xml(xml_string)
    
    if "error" in result:
        print(f"XML parsing error: {result['error']}")
    
    elif not result["valid"]:
        print("Invalid XML")
    
    return result